const inputJson = $input.first().json;

const update = 
  inputJson?.body?.[0] ||
  inputJson?.body ||
  inputJson?.[0] ||
  inputJson;

const callbackQuery = update?.callback_query;
if (!callbackQuery) {
  throw new Error(`No callback_query found. Raw input: ${JSON.stringify(inputJson)}`);
}

const messageText = callbackQuery.message.text;

// --- Action + Ticket ID from callback data ---
const callbackData    = callbackQuery.data;
const underscoreIndex = callbackData.indexOf('_');
const action          = callbackData.substring(0, underscoreIndex);
const ticketId        = callbackData.substring(underscoreIndex + 1);

// --- Agent ---
const agentId       = callbackQuery.from.id;
const agentUsername = callbackQuery.from.username;

// --- Message identifiers ---
const messageId = callbackQuery.message.message_id;
const chatId    = callbackQuery.message.chat.id;

// --- Parse fields from message text ---
const extract = (label, text) => {
  const regex = new RegExp(`${label}:\\s*(.+)`);
  const match = text.match(regex);
  return match ? match[1].trim() : "";
};

// From: Melson Wang (melsonwang@gmail.com)
const fromLine      = messageText.match(/From:\s*(.+?)\s*\((.+?)\)/);
const customerName  = fromLine ? fromLine[1].trim() : "";
const customerEmail = fromLine ? fromLine[2].trim() : "";

// Extract ticket id from message text as backup
const ticketIdFromText = extract("Ticket id", messageText) || ticketId;

const subject = extract("Subject", messageText);
const persona = extract("Persona", messageText);
const theme   = extract("Theme",   messageText);

// Order ID — optional, may not be present
const orderIdLine = messageText.match(/Order ID[^:]*:\s*(.+)/);
const orderId = orderIdLine ? orderIdLine[1].trim() : null;

// Customer message — stops at Gap summary, Draft reply, dashes, or end of string
const customerMessageMatch = messageText.match(/Customer message:\s*([\s\S]*?)(?=\nGap summary:|\nDraft reply:|─{5,}|$)/);
const customerMessage = customerMessageMatch
  ? customerMessageMatch[1].trim()
  : "";

// Draft reply — stops at Gap summary, dashes, or end of string
const draftReplyMatch = messageText.match(/Draft reply:\s*([\s\S]*?)(?=\nGap summary:|─{5,}|$)/);
const draftReply = draftReplyMatch ? draftReplyMatch[1].trim() : "";

// Gap summary — everything after "Gap summary:" if present
const gapSummaryMatch = messageText.match(/Gap summary:\s*([\s\S]+?)(?:─{5,}|$)/);
const gapSummary = gapSummaryMatch ? gapSummaryMatch[1].trim() : "";

return {
  action,
  ticketId:      ticketIdFromText,
  agentId,
  agentUsername,
  messageId,
  chatId,
  customerName,
  customerEmail,
  subject,
  persona,
  theme,
  orderId,
  customerMessage,
  draftReply,
  gapSummary,
};

const data = $input.first().json;

const stripHtml = (str) => (str || "").replace(/<\/?[^>]+(>|$)/g, "").trim();

const customerName  = stripHtml(data.customerName);
const customerEmail = stripHtml(data.customerEmail);
const subject       = stripHtml(data.subject);
const persona       = stripHtml(data.persona);
const theme         = stripHtml(data.theme);
const action        = data.action;

const rawDraft = stripHtml(data.draftReply);

// Format email with proper line breaks
const formatEmailHtml = (text) => {
  // Normalize any existing newlines
  let formatted = text.trim();

  // Break after greeting line (ends with "that." or "!" before body)
  formatted = formatted.replace(
    /(Hi .+?[.!])\s+/,
    "$1<br><br>"
  );

  // Break before "Warm regards" / "Best regards" / "Kind regards"
  formatted = formatted.replace(
    /\s+(Warm regards|Best regards|Kind regards|Regards)/,
    "<br><br>$1"
  );

  // Break between sign-off and name/team
  formatted = formatted.replace(
    /(Warm regards|Best regards|Kind regards|Regards),\s+/,
    "$1,<br>"
  );

  return `<p style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#333;">${formatted}</p>`;
};

const htmlBody = formatEmailHtml(rawDraft);

return {
  action,
  customerName,
  customerEmail,
  subject,
  persona,
  theme,
  htmlBody,
  plainBody: rawDraft,
};

// ============================================================
// BOLDR — Workflow 2: Parse Edit Instruction
// Code node: runs after "Send and Wait for Response" (edit node)
// Place this BEFORE the Qwen HTTP Request node
// ============================================================

// ── Pull fields ───────────────────────────────────────────────
const agent_input    = $('edit').first().json.data.text.trim();
const original_draft = $('Switch').first().json.draftReply;
const customer_name  = $('Switch').first().json.customerName;
const customer_email = $('Switch').first().json.customerEmail;
const subject        = $('Switch').first().json.subject;
const ticket_id      = $('Switch').first().json.id;

// ── Get first name safely ────────────────────────────────────
const first_name = (customer_name && customer_name.trim())
  ? customer_name.split(' ')[0]
  : 'there';

// ── Detect edit mode ─────────────────────────────────────────
// Pattern: "X to Y" or "edit X to Y" — partial replacement
const editPattern = /^(?:edit\s+)?(.+?)\s+to\s+(.+)$/is;
const match = agent_input.match(editPattern);

// Instruction-style: starts with action verbs or question words
const isInstruction = /^(can you|please|change|fix|remove|replace|update|make|add|rewrite|shorten|use|ensure|correct|adjust)/i.test(agent_input);

// Full email: long or has greeting/sign-off
const looksLikeFullEmail = (
  agent_input.length > 200 ||
  /^(hi |hello |dear )/i.test(agent_input) ||
  /(warm regards|best regards|kind regards|boldr customer service)/i.test(agent_input)
);

let edit_mode;
let old_text       = '';
let new_text       = '';
let full_replacement = '';
let instruction    = '';

if (looksLikeFullEmail) {
  edit_mode = 'full_replacement';
  full_replacement = agent_input;
} else if (match && !isInstruction) {
  edit_mode = 'partial_replacement';
  old_text = match[1].trim();
  new_text = match[2].trim();
} else if (isInstruction || !match) {
  edit_mode = 'instruction';
  instruction = agent_input;
} else {
  edit_mode = 'full_replacement';
  full_replacement = agent_input;
}

// ── Build Qwen prompt ─────────────────────────────────────────
let qwen_prompt = '';

if (edit_mode === 'full_replacement') {
  qwen_prompt = `You are a proofreader for BOLDR, a premium Singapore watch brand.
A customer service agent has written a replacement email reply. Clean it up slightly for BOLDR brand voice — keep it friendly, direct, and professional. Do not change the meaning or add information.

Rules:
- Ensure the email opens with "Hi ${first_name}, thanks for reaching out! Happy to help with that." if no greeting exists
- The greeting must be on its own line followed by a blank line
- Each distinct point or thought must be its own paragraph with a blank line between them
- The sign-off "Warm regards, BOLDR Customer Service" must be on its own line preceded by a blank line
- Keep it friendly, direct, and professional
- Do not write the entire reply as one block of text

Return ONLY the final cleaned email text. No JSON, no explanation, no code fences.

Agent's replacement:
${full_replacement}`;

} else if (edit_mode === 'partial_replacement') {
  qwen_prompt = `You are a proofreader for BOLDR, a premium Singapore watch brand.
A customer service agent wants to make a specific edit to a draft email reply.

Original draft:
${original_draft}

Agent instruction:
Change "${old_text}" to "${new_text}"

Rules:
- Apply ONLY the requested change, do not alter anything else
- Ensure the email opens with "Hi ${first_name}, thanks for reaching out! Happy to help with that." if no greeting exists
- The greeting must be on its own line followed by a blank line
- Each distinct point or thought must be its own paragraph with a blank line between them
- The sign-off "Warm regards, BOLDR Customer Service" must be on its own line preceded by a blank line
- Do not write the entire reply as one block of text

Return ONLY the final updated email text. No JSON, no explanation, no code fences.`;

} else {
  // instruction mode — Qwen interprets what the agent meant
  qwen_prompt = `You are a proofreader for BOLDR, a premium Singapore watch brand.
A customer service agent wants to edit a draft email reply. Read their instruction carefully and apply the change to the original draft.

Original draft:
${original_draft}

Agent instruction:
"${instruction}"

Rules:
- Apply only what the agent asked for
- Ensure the email opens with "Hi ${first_name}, thanks for reaching out! Happy to help with that." if no greeting exists
- The greeting must be on its own line followed by a blank line
- Each distinct point or thought must be its own paragraph with a blank line between them
- The sign-off "Warm regards, BOLDR Customer Service" must be on its own line preceded by a blank line
- Do not add new information not in the original draft
- Keep BOLDR brand voice — friendly, direct, premium
- If the instruction is unclear, make the most reasonable interpretation
- Do not write the entire reply as one block of text

Return ONLY the final updated email text. No JSON, no explanation, no code fences.`;
}

// ── Return everything forward ─────────────────────────────────
return [{
  json: {
    qwen_prompt,
    edit_mode,
    original_draft,
    first_name,
    customer_name,
    customer_email,
    subject,
    ticket_id,
  }
}];

