const text = $input.item.json.data.text;

// Split into sentences and build paragraphs
const sentences = text.split(/(?<=[.!?])\s+/);

// Extract greeting (first sentence)
const greeting = sentences[0];

// Extract sign-off (last two lines usually "Best, Boldr...")
const signOff = text.match(/(Best[,.][\s\S]*?)$/i)?.[1] || '';

// Get body (everything between greeting and sign-off)
const bodyText = text
  .replace(greeting, '')
  .replace(signOff, '')
  .trim();

// Split body into paragraphs by \n\n or logical sentence groups
const paragraphs = bodyText
  .split(/\n\n+/)
  .map(p => p.trim())
  .filter(p => p.length > 0)
  .map(p => `<p>${p}</p>`)
  .join('\n');

// Bold key terms
const boldTerms = [
  'ISO 764',
  'not shielded',
  'strongly advise against',
  'Venture Titanium',
  'MRI',
];

let formattedBody = paragraphs;
boldTerms.forEach(term => {
  formattedBody = formattedBody.replaceAll(term, `<strong>${term}</strong>`);
});

const html = `
<p>${greeting}</p>
${formattedBody}
${signOff ? `<p>${signOff.replace(/\n/g, '<br>')}</p>` : ''}
`.trim();

return { json: { ...$input.item.json, formattedEmail: html } };

const customerMessage = $('spilt items').item.json.customerMessage;
const staffReply = $('Code in JavaScript1').item.json.formattedEmail;

return {
  json: {
    model: "qwen-plus",
    messages: [
      {
        role: "system",
content: "You are a knowledge base builder. Given a customer email and a staff response, extract and format them as a clean Q&A pair. Return only a JSON object with exactly three fields: 'question', 'answer', and 'theme'. For theme, you MUST pick exactly one from this list: product_general, strap_compatibility, materials_safety, order_status, servicing, engraving. No other values are allowed. No extra text."
      },
      {
        role: "user",
        content: `Customer Email:\n${customerMessage}\n\nStaff Response:\n${staffReply}`
      }
    ],
    temperature: 0.2,
    response_format: {
      type: "json_object"
    }
  }
};

const raw = $input.item.json.choices[0].message.content;
const parsed = JSON.parse(raw);

return {
  json: {
    question: parsed.question,
    answer: parsed.answer,
    theme: parsed.theme
  }
};

